import{_ as e,o as i,c as l,a0 as t}from"./chunks/framework.CSGB4SNl.js";const _=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"java/eight-legged essay/java-hot200-day05.md","filePath":"java/eight-legged essay/java-hot200-day05.md"}'),s={name:"java/eight-legged essay/java-hot200-day05.md"};function r(n,a,o,d,h,c){return i(),l("div",null,[...a[0]||(a[0]=[t('<h4 id="spring的启动过程" tabindex="-1">spring的启动过程 <a class="header-anchor" href="#spring的启动过程" aria-label="Permalink to &quot;spring的启动过程&quot;">​</a></h4><ol><li>先读取配置文件，可以是xml、javaConfig、@CompontScan扫描的包路径，并加载容器中的BeanDefintions</li><li>解析BeanDefintions，拿出里面的每个Bean对象，包括类名、相互的依赖关系、作用域初始化方式等</li><li>实例化Bean，单例的默认在容器的就已经全部示例化好</li><li>依赖注入，根据各个Bean之间的依赖关系进行注入</li><li>执行Bean后置处理器，容器会遍历所有的Bean后置处理器，在Bean初始化前后分别调用两个方法，aop代理就是在这个阶段织入的</li><li>初始化回调，先注入@PostConstucut标注的方法</li><li>所有Bean初始化完成后容器发布ContenxtRefureshuEvent事件，应用就可以正式对外服务了</li><li>某个Bean创建失败怎么办:整个容器就启动失败了，包含之前创建的所有Bean一并销毁,或者可以用@Lazy延迟到真正使用时再创建</li></ol><h4 id="redis集群的实现原理是什么" tabindex="-1">Redis集群的实现原理是什么 <a class="header-anchor" href="#redis集群的实现原理是什么" aria-label="Permalink to &quot;Redis集群的实现原理是什么&quot;">​</a></h4><ol><li>本质上就是对数据进行分片存储，每个主节点负责维护一部分槽，在存储key时进行一系列取模运算，然后存储到负责这一片槽位的节点上，这样扩容缩容方便，只需将槽位过渡给其它节点</li><li>每个节点是去中心化的通信，就是每段时间随机选择邻居，然后彼此之间交换信息，来判断对方是否存活</li><li>客户端可以连接到任意一个节点，如果这个节点没找到数据的话就返回没找到的错误，并告知存在这个key的节点地址</li><li>能保证强一致性吗，不能因为复制数据是异步的，主节点写完刚刚好挂掉的话数据没来得及复制到从节点，然后又选了新节点，导致数据丢失，如果真想要一致性的话就让复制去wait一段时间吧</li></ol><h4 id="如何使用mysql的explain进行分析" tabindex="-1">如何使用mysql的EXPLAIN进行分析 <a class="header-anchor" href="#如何使用mysql的explain进行分析" aria-label="Permalink to &quot;如何使用mysql的EXPLAIN进行分析&quot;">​</a></h4><ol><li>type类型访问比如all就走了全表扫描、range就是范围、ref就是等值，const主键/唯一索引的等值查询，index扫描整棵索引树</li><li>key就是实际用到的索引</li><li>rows预估要扫描的行数</li><li>extra里面就是额外的，比如Using index就是走了覆盖索引不用回表，Using filesort说明排序没法用索引得额外排序</li><li>对一个表进行区分度计算，越大越适合单独建索引</li></ol><h4 id="redis会出现脑裂问题吗" tabindex="-1">redis会出现脑裂问题吗 <a class="header-anchor" href="#redis会出现脑裂问题吗" aria-label="Permalink to &quot;redis会出现脑裂问题吗&quot;">​</a></h4><ol><li>会，网络分区就是网络断开重连这样，此时网络断开，旧的主节点写入数据，然后哨兵集群默认这个节点挂了，通知选取新主节点，选举后主从复制，然后旧主节点变成从节点数据被覆盖丢失</li><li>解决办法：有两个参数，一个是在写入数据时要存活的从节点数，一个是写入时延迟不超过多少秒，比如主节点接收写入数据的前提是要有两个节点存活且延迟不超过10秒，否则拒绝写入返回错误提示，代码层面做重试</li><li>脑裂就是网络分区了，有网络和没网络两边都有主节点</li><li>配置那两个参数还是会出现脑裂，比如配置10秒钟但是在6秒时恢复了，然后新的主节点也选了，此时还在接收写入那就没用了这一块数据还是会丢</li><li>消息队列异步同步到mysql中，然后redis丢数据后，和mysql对账补回</li></ol><h4 id="redis如何实现分布式锁" tabindex="-1">redis如何实现分布式锁 <a class="header-anchor" href="#redis如何实现分布式锁" aria-label="Permalink to &quot;redis如何实现分布式锁&quot;">​</a></h4><ol><li>最开始的话就是哪个线程先访问就那锁，其它等待锁的释放，当然就会出现死锁，后面的话就可以加个过期时间，但是这又会出现问题，就是有锁的那一方执行时间过长，导致完成前就过期释放锁了，导致两边都有锁，当一个执行完时就把另一个锁给删了，所以后面再获取锁时要带上自己线程的名称之类的标识，再之后就可以加lua保证原子性操作，但是锁提前释放问题还是没解决，这时候就有看门狗机制来自动续期，锁不是自己的也可以停止续期，同时也能检测redis是否存活，最后就是不可重入问题会导致自己等待自己，那就加可重入锁</li></ol>',10)])])}const p=e(s,[["render",r]]);export{_ as __pageData,p as default};
